// RUN: objc3c -fobjc-version=3 -DEXE03_BUILD_BASE --emit-module EXE03Base.objcmod --module-name EXE03Base %s
// RUN: objc3c -fobjc-version=3 --import-module EXE03Base.objcmod -fsyntax-only %s
#if defined(EXE03_BUILD_BASE)
id exe03_mainToken(id seed) __attribute__((objc_executor(main)));
id exe03_mainToken(id seed) {
    return seed;
}
#else
@import EXE03Base;
id exe03_sameExecutor(id seed) __attribute__((objc_executor(main)));
id exe03_sameExecutor(id seed) {
    return exe03_mainToken(seed);
}
id exe03_missingProof(id seed) async __attribute__((objc_executor(global))) {
    return exe03_mainToken(seed);
}
#endif
